/**
 * Periodic table data for elements 1-118.
 * Compact: symbol, name, mass, group, period, category, electron config (short).
 * Categories used for color coding.
 */

export type Category =
  | 'alkali' | 'alkaline' | 'transition' | 'post-transition' | 'metalloid'
  | 'nonmetal' | 'halogen' | 'noble' | 'lanthanide' | 'actinide';

export type Element = {
  z: number;
  sym: string;
  name: string;
  mass: number;
  group: number;
  period: number;
  category: Category;
  cfg: string;
};

